window.exeSearchData = {"page-mnngex6o-hcj9e3e95":{"name":"La compra en el supermercado","isIndex":true,"fileName":"index.html","fileUrl":"index.html","prePageId":null,"nextPageId":"page-mnngex6q-3zqpxt2qa","blocks":{"block-1774287569493-45omrlmt0":{"name":"La compra en el supermercado","order":1,"idevices":{"idevice-1774287569491-k0uq16lta":{"order":1,"htmlView":"<div class=\"exe-text-template\">\n    <p>A través de la presente SdA el alumnado aprenderá el desarrollo competencias y habilidades como: <br />comunicación oral, la expresión escrita, el uso del dinero, el cálculo y el conocimiento de las <br />partes de un supermercado.</p>\n<p><img src=\"{{context_path}}/content/resources/supermercado 2..jpg\" width=\"845\" height=\"472\" alt=\"\" /></p>\n</div>","jsonProperties":"{\"ideviceId\":\"idevice-1774287569491-k0uq16lta\",\"textInfoDurationInput\":\"\",\"textInfoDurationTextInput\":\"Duración\",\"textInfoParticipantsInput\":\"\",\"textInfoParticipantsTextInput\":\"Agrupamiento\",\"textTextarea\":\"<p>A través de la presente SdA el alumnado aprenderá el desarrollo competencias y habilidades como: <br />comunicación oral, la expresión escrita, el uso del dinero, el cálculo y el conocimiento de las <br />partes de un supermercado.</p>\\n<p><img src=\\\"{{context_path}}/content/resources/supermercado 2..jpg\\\" width=\\\"845\\\" height=\\\"472\\\" alt=\\\"\\\" /></p>\",\"textFeedbackInput\":\"Mostrar retroalimentación\",\"textFeedbackTextarea\":\"\"}"}}}}},"page-mnngex6q-3zqpxt2qa":{"name":"Presentación de la SdA","isIndex":false,"fileName":"presentacion-de-la-sda.html","fileUrl":"html/presentacion-de-la-sda.html","prePageId":"page-mnngex6o-hcj9e3e95","nextPageId":"page-mnngex6r-zvxy55sl2","blocks":{"block-1774288832434-pfxnhrbcm":{"name":"Texto","order":1,"idevices":{"idevice-1774288832429-n9i4sk1qg":{"order":1,"htmlView":"<div class=\"exe-text-template\">\n    <p>El siguiente póster describe los elementos fundamentales de la SdA a desarrollar; desde su centro de interés, su temporalización, las áreas implicadas y la importancia que tiene su desarrollo en el alumnado con NEE del aula específica de modalidad c o aula específica.</p>\n<p><br /></p>\n<p><img src=\"{{context_path}}/content/resources/La compra en el supermercado (1).png\" width=\"843\" height=\"474\" alt=\"\" /></p>\n</div>","jsonProperties":"{\"ideviceId\":\"idevice-1774288832429-n9i4sk1qg\",\"textInfoDurationInput\":\"\",\"textInfoDurationTextInput\":\"Duración\",\"textInfoParticipantsInput\":\"\",\"textInfoParticipantsTextInput\":\"Agrupamiento\",\"textTextarea\":\"<p>El siguiente póster describe los elementos fundamentales de la SdA a desarrollar; desde su centro de interés, su temporalización, las áreas implicadas y la importancia que tiene su desarrollo en el alumnado con NEE del aula específica de modalidad c o aula específica.</p>\\n<p><br /></p>\\n<p><img src=\\\"{{context_path}}/content/resources/La compra en el supermercado (1).png\\\" width=\\\"843\\\" height=\\\"474\\\" alt=\\\"\\\" /></p>\",\"textFeedbackInput\":\"Mostrar retroalimentación\",\"textFeedbackTextarea\":\"\"}"}}}}},"page-mnngex6r-zvxy55sl2":{"name":"Mindmpap","isIndex":false,"fileName":"mindmpap.html","fileUrl":"html/mindmpap.html","prePageId":"page-mnngex6q-3zqpxt2qa","nextPageId":"page-mnngex6s-5l88vyvg9","blocks":{"block-1774289166982-uphlb859n":{"name":"Texto","order":1,"idevices":{"idevice-1774289166976-h9901cvpj":{"order":1,"htmlView":"<div class=\"exe-text-template\">\n    <p>A través del siguiente enlace de Canva podréis consultar el recorrido que haremos en cada una de las sesiones con las tareas propuestas así como el uso que se hará de las herramientas y medios tecnológicos.</p>\n<p><a href=\"https://www.canva.com/design/DAHEYCyVjLk/M4QOkmdzSqes8OLR7f1_8w/view?utm_content=DAHEYCyVjLk&utm_campaign=designshare&utm_medium=link2&utm_source=uniquelinks&utlId=h9f834d34e6\" title=\"\">https://www.canva.com/design/DAHEYCyVjLk/M4QOkmdzSqes8OLR7f1_8w/view?utm_content=DAHEYCyVjLk&utm_campaign=designshare&utm_medium=link2&utm_source=uniquelinks&utlId=h9f834d34e6</a> </p>\n<p><img src=\"{{context_path}}/content/resources/7.1. mapa mental canva.pdf\" alt=\"\" /><img src=\"{{context_path}}/content/resources/7.1. mapa mental canva.jpg\" width=\"1536\" height=\"864\" alt=\"\" /></p>\n<p><br /></p>\n<p><br /></p>\n</div>","jsonProperties":"{\"ideviceId\":\"idevice-1774289166976-h9901cvpj\",\"textInfoDurationInput\":\"\",\"textInfoDurationTextInput\":\"Duración\",\"textInfoParticipantsInput\":\"\",\"textInfoParticipantsTextInput\":\"Agrupamiento\",\"textTextarea\":\"<p>A través del siguiente enlace de Canva podréis consultar el recorrido que haremos en cada una de las sesiones con las tareas propuestas así como el uso que se hará de las herramientas y medios tecnológicos.</p>\\n<p><a href=\\\"https://www.canva.com/design/DAHEYCyVjLk/M4QOkmdzSqes8OLR7f1_8w/view?utm_content=DAHEYCyVjLk&utm_campaign=designshare&utm_medium=link2&utm_source=uniquelinks&utlId=h9f834d34e6\\\" title=\\\"\\\">https://www.canva.com/design/DAHEYCyVjLk/M4QOkmdzSqes8OLR7f1_8w/view?utm_content=DAHEYCyVjLk&utm_campaign=designshare&utm_medium=link2&utm_source=uniquelinks&utlId=h9f834d34e6</a> </p>\\n<p><img src=\\\"{{context_path}}/content/resources/7.1. mapa mental canva.pdf\\\" alt=\\\"\\\" /><img src=\\\"{{context_path}}/content/resources/7.1. mapa mental canva.jpg\\\" width=\\\"1536\\\" height=\\\"864\\\" alt=\\\"\\\" /></p>\\n<p><br /></p>\\n<p><br /></p>\",\"textFeedbackInput\":\"Mostrar retroalimentación\",\"textFeedbackTextarea\":\"\"}"}}},"block-1774290350908-1vvmbmxpo":{"name":"Galería de imágenes","order":1,"idevices":{"idevice-1774290350905-sza9j5wd0":{"order":1,"htmlView":"<!-- Idevice Example template start -->\n<div class=\"exe-image-gallery-template\">\n  <!-- Idevice content start -->\n  \n            <div class=\"imageGallery-IDevice\">\n                <div class=\"imageGallery-body\">\n                </div>\n            </div>\n  <!-- Idevice content end -->\n</div>\n<!-- Idevice Example template end -->","jsonProperties":"{\"ideviceId\":\"idevice-1774290350905-sza9j5wd0\"}"}}}}},"page-mnngex6s-5l88vyvg9":{"name":"Seguridad en las redes","isIndex":false,"fileName":"seguridad-en-las-redes.html","fileUrl":"html/seguridad-en-las-redes.html","prePageId":"page-mnngex6r-zvxy55sl2","nextPageId":"page-mnngex6s-vk73pe2z4","blocks":{"block-1774365528200-9gdy1038a":{"name":"Estar seguro","order":1,"idevices":{"idevice-1774365528198-l2c776onx":{"order":1,"htmlView":"<div class=\"exe-text-template\">\n    <p><br />Como hemos hablado con anterioridad, el trabajo con internet y medios digitales es fundamental para el desarrollo de nuestras capacidades. Sin embargo, un consumo prudente de las mismas es necesario. Tal como se acordó en la SdA previa, nuestro trabajo se regirá por 8 pautas de seguridad en redes. </p>\n<p>Incluyo la infografía que elaboramos entre todos para que sea recordada.</p>\n<p><img src=\"{{context_path}}/content/resources/Seguridad en las redes.png\" width=\"734\" height=\"1556\" alt=\"\" /></p>\n</div>","jsonProperties":"{\"ideviceId\":\"idevice-1774365528198-l2c776onx\",\"textInfoDurationInput\":\"\",\"textInfoDurationTextInput\":\"Duración\",\"textInfoParticipantsInput\":\"\",\"textInfoParticipantsTextInput\":\"Agrupamiento\",\"textTextarea\":\"<p><br />Como hemos hablado con anterioridad, el trabajo con internet y medios digitales es fundamental para el desarrollo de nuestras capacidades. Sin embargo, un consumo prudente de las mismas es necesario. Tal como se acordó en la SdA previa, nuestro trabajo se regirá por 8 pautas de seguridad en redes. </p>\\n<p>Incluyo la infografía que elaboramos entre todos para que sea recordada.</p>\\n<p><img src=\\\"{{context_path}}/content/resources/Seguridad en las redes.png\\\" width=\\\"734\\\" height=\\\"1556\\\" alt=\\\"\\\" /></p>\",\"textFeedbackInput\":\"Mostrar retroalimentación\",\"textFeedbackTextarea\":\"\"}"}}}}},"page-mnngex6s-vk73pe2z4":{"name":"Sesiones","isIndex":false,"fileName":"sesiones.html","fileUrl":"html/sesiones.html","prePageId":"page-mnngex6s-5l88vyvg9","nextPageId":"page-mnngex6t-qyqcl7xjp","blocks":{"block-1774452096572-44todxt0q":{"name":"Texto","order":1,"idevices":{"idevice-1774452096568-vt8ndlf9e":{"order":1,"htmlView":"","jsonProperties":"{}"}}}}},"page-mnngex6t-qyqcl7xjp":{"name":"Sesiones","isIndex":false,"fileName":"sesiones-2.html","fileUrl":"html/sesiones-2.html","prePageId":"page-mnngex6s-vk73pe2z4","nextPageId":"page-mnngex6t-d6b4etmrj","blocks":{"block-1774365852337-4a489qdy9":{"name":"¡Comencemos a trabajar!","order":1,"idevices":{"idevice-1774365852335-orp9clbzw":{"order":1,"htmlView":"<div class=\"exe-text-template\">\n    <p><br />En este apartado encontraréis distintos desplegables con cada una de las habilidades o aspectos fundamentales a trabajar en la situación de aprendizaje de <strong>La compra en el supermercado</strong>. </p>\n<p>Como podréis comprobar, la tarea se encuentra descrita y además podréis tener información complementaria como:</p>\n<p>- Duración de la actividad</p>\n<p>- Agrupamientos</p>\n<p>- Recursos digitales</p>\n<p>- Enlaces interesantes</p>\n<p> </p>\n<p>Dicho esto... empecemos a comprar!!!!</p>\n</div>","jsonProperties":"{\"ideviceId\":\"idevice-1774365852335-orp9clbzw\",\"textInfoDurationInput\":\"\",\"textInfoDurationTextInput\":\"Duración\",\"textInfoParticipantsInput\":\"\",\"textInfoParticipantsTextInput\":\"Agrupamiento\",\"textTextarea\":\"<p><br />En este apartado encontraréis distintos desplegables con cada una de las habilidades o aspectos fundamentales a trabajar en la situación de aprendizaje de <strong>La compra en el supermercado</strong>. </p>\\n<p>Como podréis comprobar, la tarea se encuentra descrita y además podréis tener información complementaria como:</p>\\n<p>- Duración de la actividad</p>\\n<p>- Agrupamientos</p>\\n<p>- Recursos digitales</p>\\n<p>- Enlaces interesantes</p>\\n<p> </p>\\n<p>Dicho esto... empecemos a comprar!!!!</p>\",\"textFeedbackInput\":\"Mostrar retroalimentación\",\"textFeedbackTextarea\":\"\"}"}}}}},"page-mnngex6t-d6b4etmrj":{"name":"Introducción a la SdA. Partes del supermercado","isIndex":false,"fileName":"introduccion-a-la-sda-partes-del-supermercado.html","fileUrl":"html/introduccion-a-la-sda-partes-del-supermercado.html","prePageId":"page-mnngex6t-qyqcl7xjp","nextPageId":"page-mnngex6t-wfl0u487z","blocks":{"block-1774366104351-j06d2o5yn":{"name":"Tiempo 30 minutos.  Agrupamiento por parejas de dos.","order":1,"idevices":{"idevice-1774366104350-kzjqby9qr":{"order":1,"htmlView":"<div class=\"exe-text-template\">\n    <p><br /></p>\n<p>Para comenzar la SdA es imprescindible tener en cuenta los conocimientos previos del grupo. El alumnado ve un video de personas realizando las compras en un supermercado, las sesiones del supermercado y todas las habilidades necesarias para hacer la compra de manera correcta. Enlace del vídeo: </p>\n<p><a href=\"https://youtu.be/Lljb-wyxZNk?is=uqD6mRV08-IK3RZC\" title=\"\">https://youtu.be/Lljb-wyxZNk?is=uqD6mRV08-IK3RZC</a></p>\n<p>Después se les pide que realicen la siguiente ficha sobre las partes del supermercado. </p>\n<p><a href=\"https://www.liveworksheets.com/worksheet/es/autonomia-personal/1402859\" title=\"\">https://www.liveworksheets.com/worksheet/es/autonomia-personal/1402859</a></p>\n</div>","jsonProperties":"{\"ideviceId\":\"idevice-1774366104350-kzjqby9qr\",\"textInfoDurationInput\":\"\",\"textInfoDurationTextInput\":\"Duración\",\"textInfoParticipantsInput\":\"\",\"textInfoParticipantsTextInput\":\"Agrupamiento\",\"textTextarea\":\"<p><br /></p>\\n<p>Para comenzar la SdA es imprescindible tener en cuenta los conocimientos previos del grupo. El alumnado ve un video de personas realizando las compras en un supermercado, las sesiones del supermercado y todas las habilidades necesarias para hacer la compra de manera correcta. Enlace del vídeo: </p>\\n<p><a href=\\\"https://youtu.be/Lljb-wyxZNk?is=uqD6mRV08-IK3RZC\\\" title=\\\"\\\">https://youtu.be/Lljb-wyxZNk?is=uqD6mRV08-IK3RZC</a></p>\\n<p>Después se les pide que realicen la siguiente ficha sobre las partes del supermercado. </p>\\n<p><a href=\\\"https://www.liveworksheets.com/worksheet/es/autonomia-personal/1402859\\\" title=\\\"\\\">https://www.liveworksheets.com/worksheet/es/autonomia-personal/1402859</a></p>\",\"textFeedbackInput\":\"Mostrar retroalimentación\",\"textFeedbackTextarea\":\"\"}"}}}}},"page-mnngex6t-wfl0u487z":{"name":"El reconocimiento de las monedas.","isIndex":false,"fileName":"el-reconocimiento-de-las-monedas.html","fileUrl":"html/el-reconocimiento-de-las-monedas.html","prePageId":"page-mnngex6t-d6b4etmrj","nextPageId":"page-mnngex6u-00mzmlask","blocks":{"block-1774367984336-4uxqeestt":{"name":"Tiempo: 2 horas. Agrupamiento: individual","order":1,"idevices":{"idevice-1774367984334-c1ksffsb2":{"order":1,"htmlView":"<div class=\"exe-text-template\">\n    <p> Se les presentará al alumnado monedas de juguete, donde aparezcan las monedas de los <br />céntimos: <br />- 1 céntimo <br />- 2 céntimos. <br />- 5 céntimos. <br />- 10 céntimos. <br />- 20 céntimos. <br />- 50 céntimos. <br />- 1 euro. <br />- 2 euros. </p>\n<p>Además  como apoyo a nuestra explicación usaremos el siguiente enlace para explicar el uso de las monedas en la PDI: </p>\n<p>Enlace:</p>\n<p><a href=\"https://youtube.com/shorts/jxHa12Enhb4?feature=shared\" title=\"\">https://youtube.com/shorts/jxHa12Enhb4?feature=shared</a></p>\n<p><br />Una vez presentadas las monedas tendrán que diferenciar los céntimos y los euros para ello <br />realizaremos actividades en la pizarra donde de azul vayan los euros y de rojo los céntimos. </p>\n<p> Además, realizaremos una actividad en la aplicación j. clic para trabajar el manejo del dinero en la PDI. </p>\n<p><a href=\"https://clic.xtec.cat/projects/eurobesp/jclic.js/index.html\" title=\"\">https://clic.xtec.cat/projects/eurobesp/jclic.js/index.html</a></p>\n<p><img src=\"{{context_path}}/content/resources/dinero.jpg\" width=\"411\" height=\"274\" alt=\"\" /><br /></p>\n<p><br /></p>\n</div>","jsonProperties":"{\"ideviceId\":\"idevice-1774367984334-c1ksffsb2\",\"textInfoDurationInput\":\"\",\"textInfoDurationTextInput\":\"Duración\",\"textInfoParticipantsInput\":\"\",\"textInfoParticipantsTextInput\":\"Agrupamiento\",\"textTextarea\":\"<p> Se les presentará al alumnado monedas de juguete, donde aparezcan las monedas de los <br />céntimos: <br />- 1 céntimo <br />- 2 céntimos. <br />- 5 céntimos. <br />- 10 céntimos. <br />- 20 céntimos. <br />- 50 céntimos. <br />- 1 euro. <br />- 2 euros. </p>\\n<p>Además  como apoyo a nuestra explicación usaremos el siguiente enlace para explicar el uso de las monedas en la PDI: </p>\\n<p>Enlace:</p>\\n<p><a href=\\\"https://youtube.com/shorts/jxHa12Enhb4?feature=shared\\\" title=\\\"\\\">https://youtube.com/shorts/jxHa12Enhb4?feature=shared</a></p>\\n<p><br />Una vez presentadas las monedas tendrán que diferenciar los céntimos y los euros para ello <br />realizaremos actividades en la pizarra donde de azul vayan los euros y de rojo los céntimos. </p>\\n<p> Además, realizaremos una actividad en la aplicación j. clic para trabajar el manejo del dinero en la PDI. </p>\\n<p><a href=\\\"https://clic.xtec.cat/projects/eurobesp/jclic.js/index.html\\\" title=\\\"\\\">https://clic.xtec.cat/projects/eurobesp/jclic.js/index.html</a></p>\\n<p><img src=\\\"{{context_path}}/content/resources/dinero.jpg\\\" width=\\\"411\\\" height=\\\"274\\\" alt=\\\"\\\" /><br /></p>\\n<p><br /></p>\",\"textFeedbackInput\":\"Mostrar retroalimentación\",\"textFeedbackTextarea\":\"\"}"}}},"block-1774369169912-tpjbewsdv":{"name":"Galería de imágenes","order":1,"idevices":{"idevice-1774369169910-21yeningt":{"order":1,"htmlView":"","jsonProperties":"{}"}}}}},"page-mnngex6u-00mzmlask":{"name":"El cálculo de sumas y restas","isIndex":false,"fileName":"el-calculo-de-sumas-y-restas.html","fileUrl":"html/el-calculo-de-sumas-y-restas.html","prePageId":"page-mnngex6t-wfl0u487z","nextPageId":"page-mnngex6u-djr3wlaic","blocks":{"block-1774369568902-kij7nk689":{"name":"Tiempo: 2 horas. Agrupamientos: individual.","order":1,"idevices":{"idevice-1774369568899-srxfxxl8b":{"order":1,"htmlView":"<div class=\"exe-text-template\">\n    <p>En primer lugar se repasan y vuelven a explicar el concepto de sumas y restar en la pizarra. En segundo lugar se repasan los conceptos clave de la suma y resta en la PDI, a través del siguiente enlace:</p>\n<p><a href=\"https://youtu.be/k46QCr1GofU?feature=shared\" title=\"\">https://youtu.be/k46QCr1GofU?feature=shared</a></p>\n<p>Se le elabora una ficha PDI a través de herramienta digital liveworksheet para las sumas y <br />restas de los euros y céntimos. </p>\n<p>Enlace de la ficha:</p>\n<p><a href=\"https://www.liveworksheets.com/worksheet/es/math-addition-and-subtraction/8225744#google_vignette\" title=\"\">https://www.liveworksheets.com/worksheet/es/math-addition-and-subtraction/8225744#google_vignette</a></p>\n<p>Finalmente se le corrige la ficha a través de la misma herramienta digital.</p>\n<p><img src=\"{{context_path}}/content/resources/sumas y restas.png\" width=\"471\" height=\"200\" alt=\"\" /></p>\n<p><br /></p>\n</div>","jsonProperties":"{\"ideviceId\":\"idevice-1774369568899-srxfxxl8b\",\"textInfoDurationInput\":\"\",\"textInfoDurationTextInput\":\"Duración\",\"textInfoParticipantsInput\":\"\",\"textInfoParticipantsTextInput\":\"Agrupamiento\",\"textTextarea\":\"<p>En primer lugar se repasan y vuelven a explicar el concepto de sumas y restar en la pizarra. En segundo lugar se repasan los conceptos clave de la suma y resta en la PDI, a través del siguiente enlace:</p>\\n<p><a href=\\\"https://youtu.be/k46QCr1GofU?feature=shared\\\" title=\\\"\\\">https://youtu.be/k46QCr1GofU?feature=shared</a></p>\\n<p>Se le elabora una ficha PDI a través de herramienta digital liveworksheet para las sumas y <br />restas de los euros y céntimos. </p>\\n<p>Enlace de la ficha:</p>\\n<p><a href=\\\"https://www.liveworksheets.com/worksheet/es/math-addition-and-subtraction/8225744#google_vignette\\\" title=\\\"\\\">https://www.liveworksheets.com/worksheet/es/math-addition-and-subtraction/8225744#google_vignette</a></p>\\n<p>Finalmente se le corrige la ficha a través de la misma herramienta digital.</p>\\n<p><img src=\\\"{{context_path}}/content/resources/sumas y restas.png\\\" width=\\\"471\\\" height=\\\"200\\\" alt=\\\"\\\" /></p>\\n<p><br /></p>\",\"textFeedbackInput\":\"Mostrar retroalimentación\",\"textFeedbackTextarea\":\"\"}"}}}}},"page-mnngex6u-djr3wlaic":{"name":"La elaboración de la lista de la compra y exposición","isIndex":false,"fileName":"la-elaboracion-de-la-lista-de-la-compra-y-exposici.html","fileUrl":"html/la-elaboracion-de-la-lista-de-la-compra-y-exposici.html","prePageId":"page-mnngex6u-00mzmlask","nextPageId":"page-mnngex6v-jotkbqkyx","blocks":{"block-1774374623163-klp7c2cl3":{"name":"Agrupamiento: por parejas. Tiempo: 2 horas.","order":1,"idevices":{"idevice-1774374623159-tlvsnsqks":{"order":1,"htmlView":"<div class=\"exe-text-template\">\n    <p>Se les enseñará a elaborar una lista de la compra donde aparezcan los distintos tipos de alimentos del supermercado en canva. Después, le pedimos que elaboren una lista de la compra en casa a través de esta herramienta digital y la suban al classroom. Una vez que la evaluemos, posteriormente la imprimiremos para que la rellenen en clase y vayamos hacer la compra. <br title=\"\" /><a href=\"https://www.canva.com/design/DAHE4blOTeI/Yhie3oVlTt3l7zYPv1VVNQ/edit?utm_content=DAHE4blOTeI&utm_campaign=designshare&utm_medium=link2&utm_source=sharebutton\">https://www.canva.com/design/DAHE4blOTeI/Yhie3oVlTt3l7zYPv1VVNQ/edit?utm_content=DAHE4blOTeI&utm_campaign=designshare&utm_medium=link2&utm_source=sharebutton</a><br /></p>\n<p><br /></p>\n<p><img src=\"{{context_path}}/content/resources/carrito.avif\" width=\"471\" height=\"246\" alt=\"\" /><br /></p>\n<p>Además, luego la familia le tendrá que dar dinero en un monedero para ir hacer la compra el día que fijamos para realizar la salida complementaria. </p>\n</div>","jsonProperties":"{\"ideviceId\":\"idevice-1774374623159-tlvsnsqks\",\"textInfoDurationInput\":\"\",\"textInfoDurationTextInput\":\"Duración\",\"textInfoParticipantsInput\":\"\",\"textInfoParticipantsTextInput\":\"Agrupamiento\",\"textTextarea\":\"<p>Se les enseñará a elaborar una lista de la compra donde aparezcan los distintos tipos de alimentos del supermercado en canva. Después, le pedimos que elaboren una lista de la compra en casa a través de esta herramienta digital y la suban al classroom. Una vez que la evaluemos, posteriormente la imprimiremos para que la rellenen en clase y vayamos hacer la compra. <br title=\\\"\\\" /><a href=\\\"https://www.canva.com/design/DAHE4blOTeI/Yhie3oVlTt3l7zYPv1VVNQ/edit?utm_content=DAHE4blOTeI&utm_campaign=designshare&utm_medium=link2&utm_source=sharebutton\\\">https://www.canva.com/design/DAHE4blOTeI/Yhie3oVlTt3l7zYPv1VVNQ/edit?utm_content=DAHE4blOTeI&utm_campaign=designshare&utm_medium=link2&utm_source=sharebutton</a><br /></p>\\n<p><br /></p>\\n<p><img src=\\\"{{context_path}}/content/resources/carrito.avif\\\" width=\\\"471\\\" height=\\\"246\\\" alt=\\\"\\\" /><br /></p>\\n<p>Además, luego la familia le tendrá que dar dinero en un monedero para ir hacer la compra el día que fijamos para realizar la salida complementaria. </p>\",\"textFeedbackInput\":\"Mostrar retroalimentación\",\"textFeedbackTextarea\":\"\"}"}}}}},"page-mnngex6v-jotkbqkyx":{"name":"La compra en clase","isIndex":false,"fileName":"la-compra-en-clase.html","fileUrl":"html/la-compra-en-clase.html","prePageId":"page-mnngex6u-djr3wlaic","nextPageId":"page-mnngex6v-uvcb54yq1","blocks":{"block-1774375240328-d59k36s9p":{"name":"Tiempo: 6o minutos","order":1,"idevices":{"idevice-1774375240321-hvcej7wbt":{"order":1,"htmlView":"<div class=\"exe-text-template\">\n    <p>En esta sesión  el alumnado deberá realizar una compra virtual en la PDI a través de la siguiente actividad<br />que aparece en la herramienta digital liveworksheet. </p>\n<p>Enlace de la actividad:</p>\n<p><a href=\"https://www.liveworksheets.com/worksheet/es/matematicas/701883\" title=\"\">https://www.liveworksheets.com/worksheet/es/matematicas/701883</a></p>\n<p></p>\n</div>","jsonProperties":"{\"ideviceId\":\"idevice-1774375240321-hvcej7wbt\",\"textInfoDurationInput\":\"\",\"textInfoDurationTextInput\":\"Duración\",\"textInfoParticipantsInput\":\"\",\"textInfoParticipantsTextInput\":\"Agrupamiento\",\"textTextarea\":\"<p>En esta sesión  el alumnado deberá realizar una compra virtual en la PDI a través de la siguiente actividad<br />que aparece en la herramienta digital liveworksheet. </p>\\n<p>Enlace de la actividad:</p>\\n<p><a href=\\\"https://www.liveworksheets.com/worksheet/es/matematicas/701883\\\" title=\\\"\\\">https://www.liveworksheets.com/worksheet/es/matematicas/701883</a></p>\\n<p></p>\",\"textFeedbackInput\":\"Mostrar retroalimentación\",\"textFeedbackTextarea\":\"\"}"}}}}},"page-mnngex6v-uvcb54yq1":{"name":"Tarea final","isIndex":false,"fileName":"tarea-final.html","fileUrl":"html/tarea-final.html","prePageId":"page-mnngex6v-jotkbqkyx","nextPageId":"page-mnngex6v-qxew3um6q","blocks":{"block-1774375487169-g7aop1zxk":{"name":"Texto","order":1,"idevices":{"idevice-1774375487167-z9mz7z0h6":{"order":1,"htmlView":"<div class=\"exe-text-template\">\n    <p>¡Ya casi estamos!</p>\n<p>Tras haber realizado cada una de las tareas propuestas y haberlas superado, es momento de trabajar en nuestro producto final.</p>\n<p>El día marcado en el calendario iremos, el alumnado junto con la PTIS y el maestro de Pedagogía Terapéutica  a <br />realizar la compra a un supermercado próximo al colegio. Previamente le entregaremos la lista de la compra creadas por ellos en canva. Además, le tendrán que dar dinero en un monedero. </p>\n<p>En esta tarea final se pondrán a prueba las siguientes habilidades y competencias: </p>\n<p>-  Habilidades sociales el saludo, la despedida, el darle dinero, la vuelta. </p>\n<p>- La autonomía personal en el desplazamiento del supermercado y encontrar los productos en la parte del supermercado. </p>\n<p><img src=\"{{context_path}}/content/resources/supermercado 2..jpg\" width=\"612\" height=\"342\" alt=\"\" /><br /></p>\n<p><br /></p>\n</div>","jsonProperties":"{\"ideviceId\":\"idevice-1774375487167-z9mz7z0h6\",\"textInfoDurationInput\":\"\",\"textInfoDurationTextInput\":\"Duración\",\"textInfoParticipantsInput\":\"\",\"textInfoParticipantsTextInput\":\"Agrupamiento\",\"textTextarea\":\"<p>¡Ya casi estamos!</p>\\n<p>Tras haber realizado cada una de las tareas propuestas y haberlas superado, es momento de trabajar en nuestro producto final.</p>\\n<p>El día marcado en el calendario iremos, el alumnado junto con la PTIS y el maestro de Pedagogía Terapéutica  a <br />realizar la compra a un supermercado próximo al colegio. Previamente le entregaremos la lista de la compra creadas por ellos en canva. Además, le tendrán que dar dinero en un monedero. </p>\\n<p>En esta tarea final se pondrán a prueba las siguientes habilidades y competencias: </p>\\n<p>-  Habilidades sociales el saludo, la despedida, el darle dinero, la vuelta. </p>\\n<p>- La autonomía personal en el desplazamiento del supermercado y encontrar los productos en la parte del supermercado. </p>\\n<p><img src=\\\"{{context_path}}/content/resources/supermercado 2..jpg\\\" width=\\\"612\\\" height=\\\"342\\\" alt=\\\"\\\" /><br /></p>\\n<p><br /></p>\",\"textFeedbackInput\":\"Mostrar retroalimentación\",\"textFeedbackTextarea\":\"\"}"}}}}},"page-mnngex6v-qxew3um6q":{"name":"Guía didáctica","isIndex":false,"fileName":"guia-didactica.html","fileUrl":"html/guia-didactica.html","prePageId":"page-mnngex6v-uvcb54yq1","nextPageId":"page-mnngex6w-ujzmpbb5e","blocks":{"block-1774457355883-e1zl2un58":{"name":"Texto","order":1,"idevices":{"idevice-1774457355878-gxqbcefin":{"order":1,"htmlView":"<div class=\"exe-text-template\">\n    <p>En el siguiente documento se aportan las tareas propuestas en esta SdA con los criterios de evaluación seleccionados.</p>\n<p><a href=\"https://docs.google.com/document/d/1_YQABwXhnSWMhDa4Xf7JUHWLrmi_itjJ5UKzyaXbgm0/edit?usp=sharing\" title=\"\">https://docs.google.com/document/d/1_YQABwXhnSWMhDa4Xf7JUHWLrmi_itjJ5UKzyaXbgm0/edit?usp=sharing</a></p>\n<p><br /></p>\n</div>","jsonProperties":"{\"ideviceId\":\"idevice-1774457355878-gxqbcefin\",\"textInfoDurationInput\":\"\",\"textInfoDurationTextInput\":\"Duración\",\"textInfoParticipantsInput\":\"\",\"textInfoParticipantsTextInput\":\"Agrupamiento\",\"textTextarea\":\"<p>En el siguiente documento se aportan las tareas propuestas en esta SdA con los criterios de evaluación seleccionados.</p>\\n<p><a href=\\\"https://docs.google.com/document/d/1_YQABwXhnSWMhDa4Xf7JUHWLrmi_itjJ5UKzyaXbgm0/edit?usp=sharing\\\" title=\\\"\\\">https://docs.google.com/document/d/1_YQABwXhnSWMhDa4Xf7JUHWLrmi_itjJ5UKzyaXbgm0/edit?usp=sharing</a></p>\\n<p><br /></p>\",\"textFeedbackInput\":\"Mostrar retroalimentación\",\"textFeedbackTextarea\":\"\"}"}}}}},"page-mnngex6w-ujzmpbb5e":{"name":"La evaluación","isIndex":false,"fileName":"la-evaluacion.html","fileUrl":"html/la-evaluacion.html","prePageId":"page-mnngex6v-qxew3um6q","nextPageId":null,"blocks":{"block-1774457576767-c8d83bmh5":{"name":"Instrumentos de Evaluación","order":1,"idevices":{"idevice-1774457576761-wwqsro9sl":{"order":1,"htmlView":"<div class=\"exe-text-template\">\n    <p>Para evaluar el desarrollo de competencia de nuestro alumnado en esta SdA, se han elaborado dos instrumentos de evaluación; una lista de cotejo a tener en cuenta en el desarrollo de las sesiones y una diana de evaluación para que el alumnado pueda participar en dicha tarea y evaluar a sus compañeros.</p>\n<p>1) Lista de cotejo:</p>\n<p><img src=\"{{context_path}}/content/resources/0.jpg\" width=\"280\" height=\"395\" alt=\"\" />   <img src=\"{{context_path}}/content/resources/1.jpg\" width=\"298\" height=\"421\" alt=\"\" /> <img src=\"{{context_path}}/content/resources/2.jpg\" width=\"161\" height=\"227\" alt=\"\" /></p>\n<p>2) Diana de Autoevaluación: </p>\n<p><img src=\"{{context_path}}/content/resources/Diana de Evaluación Educativa Autoevaluación.jpg\" width=\"370\" height=\"523\" alt=\"\" /></p>\n<p></p>\n<p></p>\n</div>","jsonProperties":"{\"ideviceId\":\"idevice-1774457576761-wwqsro9sl\",\"textInfoDurationInput\":\"\",\"textInfoDurationTextInput\":\"Duración\",\"textInfoParticipantsInput\":\"\",\"textInfoParticipantsTextInput\":\"Agrupamiento\",\"textTextarea\":\"<p>Para evaluar el desarrollo de competencia de nuestro alumnado en esta SdA, se han elaborado dos instrumentos de evaluación; una lista de cotejo a tener en cuenta en el desarrollo de las sesiones y una diana de evaluación para que el alumnado pueda participar en dicha tarea y evaluar a sus compañeros.</p>\\n<p>1) Lista de cotejo:</p>\\n<p><img src=\\\"{{context_path}}/content/resources/0.jpg\\\" width=\\\"280\\\" height=\\\"395\\\" alt=\\\"\\\" />   <img src=\\\"{{context_path}}/content/resources/1.jpg\\\" width=\\\"298\\\" height=\\\"421\\\" alt=\\\"\\\" /> <img src=\\\"{{context_path}}/content/resources/2.jpg\\\" width=\\\"161\\\" height=\\\"227\\\" alt=\\\"\\\" /></p>\\n<p>2) Diana de Autoevaluación: </p>\\n<p><img src=\\\"{{context_path}}/content/resources/Diana de Evaluación Educativa Autoevaluación.jpg\\\" width=\\\"370\\\" height=\\\"523\\\" alt=\\\"\\\" /></p>\\n<p></p>\\n<p></p>\",\"textFeedbackInput\":\"Mostrar retroalimentación\",\"textFeedbackTextarea\":\"\"}"}}}}}};